import asyncio
import json
import time
from collections import defaultdict
from dataclasses import dataclass
from typing import Dict, List, Set, Tuple
import math

@dataclass
class Player:
    id: str
    x: float
    y: float
    z: float
    health: int
    team: int
    is_alive: bool

@dataclass
class GameState:
    players: Dict[str, Player]
    timestamp: float
    game_time: float

class BattleRoyaleServer:
    def __init__(self):
        self.clients: Dict[str, asyncio.StreamWriter] = {}
        self.players: Dict[str, Player] = {}
        self.game_state = GameState({}, time.time(), 0)
        self.running = False
        self.broadcast_task = None
        self.player_id_counter = 0

    async def start_server(self, host='localhost', port=8888):
        server = await asyncio.start_server(
            self.handle_client, host, port
        )
        self.running = True
        self.broadcast_task = asyncio.create_task(self.broadcast_game_state())
        async with server:
            await server.serve_forever()

    async def handle_client(self, reader: asyncio.StreamReader, writer: asyncio.StreamWriter):
        client_id = f"client_{len(self.clients)}"
        self.clients[client_id] = writer
        
        try:
            while self.running:
                data = await reader.read(1024)
                if not data:
                    break
                
                try:
                    message = json.loads(data.decode())
                    await self.process_client_message(client_id, message)
                except json.JSONDecodeError:
                    pass
                    
        except Exception as e:
            print(f"Client error: {e}")
        finally:
            if client_id in self.clients:
                del self.clients[client_id]
            if client_id in self.players:
                del self.players[client_id]
            writer.close()
            await writer.wait_closed()

    async def process_client_message(self, client_id: str, message: Dict):
        if message.get('type') == 'join':
            player_id = f"player_{self.player_id_counter}"
            self.player_id_counter += 1
            player = Player(
                id=player_id,
                x=0.0,
                y=0.0,
                z=0.0,
                health=100,
                team=0,
                is_alive=True
            )
            self.players[player_id] = player
            self.game_state.players = self.players.copy()
            
        elif message.get('type') == 'update_position':
            player_id = message.get('player_id')
            if player_id in self.players:
                player = self.players[player_id]
                player.x = message.get('x', player.x)
                player.y = message.get('y', player.y)
                player.z = message.get('z', player.z)
                self.game_state.players = self.players.copy()

    def calculate_distance(self, pos1: Tuple[float, float, float], pos2: Tuple[float, float, float]) -> float:
        return math.sqrt((pos1[0] - pos2[0])**2 + (pos1[1] - pos2[1])**2 + (pos1[2] - pos2[2])**2)

    def is_in_line_of_sight(self, player_pos: Tuple[float, float, float], target_pos: Tuple[float, float, float], 
                          obstacles: List[Tuple[float, float, float]]) -> bool:
        # Simplified line of sight check
        return True

    async def broadcast_game_state(self):
        while self.running:
            self.game_state.timestamp = time.time()
            self.game_state.game_time += 0.1
            
            game_state_json = json.dumps({
                'type': 'game_state',
                'state': {
                    'players': {
                        pid: {
                            'id': p.id,
                            'x': p.x,
                            'y': p.y,
                            'z': p.z,
                            'health': p.health,
                            'team': p.team,
                            'is_alive': p.is_alive
                        } for pid, p in self.game_state.players.items()
                    },
                    'timestamp': self.game_state.timestamp,
                    'game_time': self.game_state.game_time
                }
            })
            
            # Send to all clients
            for client_id, writer in list(self.clients.items()):
                try:
                    writer.write(game_state_json.encode() + b'\n')
                    await writer.drain()
                except Exception:
                    if client_id in self.clients:
                        del self.clients[client_id]
            
            await asyncio.sleep(0.1)

    def get_visible_players(self, player_id: str, max_distance: float = 100.0) -> List[Dict]:
        if player_id not in self.players:
            return []
        
        player = self.players[player_id]
        visible_players = []
        
        for pid, p in self.players.items():
            if pid == player_id:
                continue
                
            distance = self.calculate_distance((player.x, player.y, player.z), (p.x, p.y, p.z))
            if distance <= max_distance:
                visible_players.append({
                    'player_id': p.id,
                    'x': p.x,
                    'y': p.y,
                    'z': p.z,
                    'health': p.health,
                    'team': p.team,
                    'is_alive': p.is_alive,
                    'distance': distance
                })
        
        return visible_players

